sEnvironment = Upper(Trim(pEnvironment));
sCreateBehavior = Upper(Trim(pCreateIfExistsBehavior));
sExportFolder = Trim(pExportFolder);
If(sEnvironment @= ''); sEnvironment = 'DEV'; EndIf;
ExecuteProcess('IMF.P.Security.LogBootstrap', 'pEnvironment', sEnvironment, 'pAction', 'BOOTSTRAP_START', 'pObjectType', 'SECURITY_MODEL', 'pObjectName', 'IMF', 'pStatus', 'INFO', 'pMessage', 'Security bootstrap started.');
ExecuteProcess('IMF.P.Security.CreateGroups', 'pEnvironment', sEnvironment, 'pCreateIfExistsBehavior', sCreateBehavior);
ExecuteProcess('IMF.P.Security.ApplyModel', 'pEnvironment', sEnvironment, 'pLogOnly', 'N');
ExecuteProcess('IMF.P.Security.ValidateGroups', 'pEnvironment', sEnvironment);
ExecuteProcess('IMF.P.Security.ValidateObjectSecurity', 'pEnvironment', sEnvironment);
ExecuteProcess('IMF.P.Security.ExportProcessMatrix', 'pEnvironment', sEnvironment, 'pOutputFile', sExportFolder | '/IMF_Process_Security_Matrix.csv');
ExecuteProcess('IMF.P.Security.ExportSecurityMatrix', 'pEnvironment', sEnvironment, 'pOutputFile', sExportFolder | '/IMF_Security_Matrix.csv');
